import socket

def handle_client(client_socket, client_address):
    # Placeholder for handling client requests
    response = b"Server Status:\nPlayer List:\n- Player1\n- Player2\nGame State: Running"
    client_socket.sendto(response, client_address)

def start_server(host='0.0.0.0', port=54321):
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    server_socket.bind((host, port))
    print(f"Server listening on {host}:{port}")

